package com.bubuyun.driver;

import android.app.*;import android.os.*;import android.content.*;import android.net.Uri;import android.graphics.*;import android.graphics.drawable.*;import android.view.*;import android.widget.*;import java.text.*;import java.util.*;

public class MainActivity extends Activity{
    LinearLayout root,content,nav;ScrollView scroll;ArrayList<Cargo> cargos=new ArrayList<>();ArrayList<Waybill> waybills=new ArrayList<>();String active="首页";int blue=Color.rgb(11,87,208),deep=Color.rgb(18,32,61),muted=Color.rgb(103,115,135),bg=Color.rgb(246,248,252),orange=Color.rgb(235,108,0);String driverName="张师傅",driverPhone="13888886666",plateNo="粤B·MVP88",driverVehicle="9.6 米厢式",driverCapacity="12 吨",driverCompany="步步云认证司机";Waybill pendingBill;
    static class Cargo{String id,owner,ownerPhone,company,from,to,loadAddr,unloadAddr,goods,weight,price,vehicleReq,loadTime,settlement,receiver,note,tag;Cargo(String id,String owner,String phone,String company,String from,String to,String loadAddr,String unloadAddr,String goods,String weight,String price,String req,String time,String settlement,String receiver,String note,String tag){this.id=id;this.owner=owner;this.ownerPhone=phone;this.company=company;this.from=from;this.to=to;this.loadAddr=loadAddr;this.unloadAddr=unloadAddr;this.goods=goods;this.weight=weight;this.price=price;this.vehicleReq=req;this.loadTime=time;this.settlement=settlement;this.receiver=receiver;this.note=note;this.tag=tag;}}
    static class Waybill{String no,status;Cargo c;Uri billImage;Waybill(String no,Cargo c,String status){this.no=no;this.c=c;this.status=status;}}
    public void onCreate(Bundle b){super.onCreate(b);seed();build();showHome();}
    void seed(){cargos.add(new Cargo("HY20260506001","李经理","13800000001","上海云仓供应链","上海","杭州","上海市青浦区华新镇华隆路1688号","杭州市余杭区良渚物流园6号库","电子配件","8 吨","¥2600","9.6 米厢式｜厢内干净｜需尾板","今天 18:00","回单后24小时结算","杭州收货仓","到仓装车，需拍照回传装货单","急装"));cargos.add(new Cargo("HY20260506002","王经理","13800000002","深圳鲜达冷链","深圳","广州","深圳市龙岗区平湖冷链园A3仓","广州市白云区江高冷库2号门","生鲜冷链","5 吨","¥1800","冷藏车｜温控2-8℃｜全程记录","今天 21:00","卸货签收后结算","广州白云冷库","整车直达，装卸各1小时","冷链"));cargos.add(new Cargo("HY20260506003","陈经理","13800000003","苏州家居集运","苏州","成都","苏州市相城区太平街道金瑞路88号","成都市新都区传化物流基地","家具整车","18 吨","¥8600","13米高栏｜带雨布绑带","明天 08:30","到付50%，回单50%","成都经销仓","轻拿轻放，严禁雨淋","长途"));waybills.add(new Waybill("YD20260506001",cargos.get(1),"运输中"));}
    int dp(int v){return(int)(v*getResources().getDisplayMetrics().density+0.5f);}String nowNo(String p){return p+new SimpleDateFormat("MMddHHmmss",Locale.CHINA).format(new Date());}
    TextView tv(String s,int sp,int c,int style){TextView v=new TextView(this);v.setText(s);v.setTextSize(sp);v.setTextColor(c);v.setTypeface(Typeface.DEFAULT,style);v.setPadding(dp(14),dp(6),dp(14),dp(6));return v;}GradientDrawable shape(int color,int r){GradientDrawable g=new GradientDrawable();g.setColor(color);g.setCornerRadius(dp(r));return g;}GradientDrawable stroke(int color,int r,int sw,int sc){GradientDrawable g=shape(color,r);g.setStroke(dp(sw),sc);return g;}Button btn(String s){Button b=new Button(this);b.setText(s);b.setTextColor(Color.WHITE);b.setTextSize(15);b.setAllCaps(false);b.setBackground(shape(blue,14));return b;}Button lightBtn(String s){Button b=new Button(this);b.setText(s);b.setTextColor(blue);b.setTextSize(15);b.setAllCaps(false);b.setBackground(stroke(Color.WHITE,14,1,Color.rgb(197,215,247)));return b;}
    void build(){root=new LinearLayout(this);root.setOrientation(LinearLayout.VERTICAL);root.setBackgroundColor(bg);setContentView(root);content=new LinearLayout(this);content.setOrientation(LinearLayout.VERTICAL);content.setPadding(dp(12),dp(8),dp(12),dp(12));scroll=new ScrollView(this);scroll.addView(content);root.addView(scroll,new LinearLayout.LayoutParams(-1,0,1));nav=new LinearLayout(this);nav.setOrientation(LinearLayout.HORIZONTAL);nav.setPadding(dp(6),dp(4),dp(6),dp(4));nav.setBackgroundColor(Color.WHITE);root.addView(nav,new LinearLayout.LayoutParams(-1,dp(64)));}
    void nav(){nav.removeAllViews();tab("首页",v->showHome());tab("发布",v->showPublish());tab("找货",v->showCargo());tab("我的",v->showMe());}void tab(String s,View.OnClickListener l){TextView t=tv((s.equals(active)?"● ":"")+s,15,s.equals(active)?blue:muted,Typeface.BOLD);t.setGravity(Gravity.CENTER);t.setOnClickListener(l);nav.addView(t,new LinearLayout.LayoutParams(0,-1,1));}void clear(String a){active=a;content.removeAllViews();nav();scroll.post(()->scroll.scrollTo(0,0));}void header(String title,String sub){TextView h=tv(title,24,deep,Typeface.BOLD);h.setPadding(dp(14),dp(12),dp(14),0);content.addView(h);TextView p=tv(sub,14,muted,0);p.setPadding(dp(14),0,dp(14),dp(8));content.addView(p);}LinearLayout card(){LinearLayout box=new LinearLayout(this);box.setOrientation(LinearLayout.VERTICAL);box.setPadding(dp(14),dp(12),dp(14),dp(12));box.setBackground(stroke(Color.WHITE,18,1,Color.rgb(232,237,247)));LinearLayout.LayoutParams lp=new LinearLayout.LayoutParams(-1,-2);lp.setMargins(0,dp(8),0,dp(8));content.addView(box,lp);return box;}void row(LinearLayout box,String k,String v){LinearLayout r=new LinearLayout(this);r.setOrientation(LinearLayout.HORIZONTAL);TextView a=tv(k,14,muted,0);TextView b=tv(v,14,deep,Typeface.BOLD);r.addView(a,new LinearLayout.LayoutParams(dp(104),-2));r.addView(b,new LinearLayout.LayoutParams(0,-2,1));box.addView(r);}String val(EditText e,String d){String s=e.getText().toString().trim();return s.length()==0?d:s;}
    void showHome(){clear("首页");header("步步云司机","高效接单，安心运输");LinearLayout dash=card();dash.setBackground(shape(blue,20));dash.addView(tv("今日收入",14,Color.rgb(218,232,255),0));dash.addView(tv("¥1,860",30,Color.WHITE,Typeface.BOLD));dash.addView(tv("运输中 "+countStatus("运输中")+" 单｜待装货 "+countStatus("待装货")+" 单｜可接货源 "+cargos.size()+" 单",14,Color.WHITE,0));TextView q=tv("常用服务",18,deep,Typeface.BOLD);q.setPadding(dp(14),dp(16),dp(14),dp(6));content.addView(q);LinearLayout r=new LinearLayout(this);r.setOrientation(LinearLayout.HORIZONTAL);content.addView(r,new LinearLayout.LayoutParams(-1,-2));mini(r,"找货大厅","浏览并接单",v->showCargo());mini(r,"发布货源","卖家发布演示",v->showPublish());content.addView(tv("推荐货源",18,deep,Typeface.BOLD));for(int i=0;i<Math.min(2,cargos.size());i++)cargoCard(cargos.get(i));}
    int countStatus(String s){int n=0;for(Waybill w:waybills)if(w.status.equals(s))n++;return n;}void mini(LinearLayout row,String t,String s,View.OnClickListener l){LinearLayout m=new LinearLayout(this);m.setOrientation(LinearLayout.VERTICAL);m.setPadding(dp(12),dp(12),dp(12),dp(12));m.setBackground(stroke(Color.WHITE,18,1,Color.rgb(232,237,247)));m.setOnClickListener(l);m.addView(tv(t,16,deep,Typeface.BOLD));m.addView(tv(s,13,muted,0));LinearLayout.LayoutParams lp=new LinearLayout.LayoutParams(0,dp(92),1);lp.setMargins(dp(4),dp(4),dp(4),dp(12));row.addView(m,lp);}
    void showCargo(){clear("找货");header("找货大厅","按路线、车型和装货时间选择货源");for(Cargo x:cargos)cargoCard(x);}void cargoCard(Cargo x){LinearLayout box=card();LinearLayout top=new LinearLayout(this);top.setGravity(Gravity.CENTER_VERTICAL);TextView route=tv(x.from+" → "+x.to,19,deep,Typeface.BOLD);top.addView(route,new LinearLayout.LayoutParams(0,-2,1));TextView tag=tv(x.tag,12,blue,Typeface.BOLD);tag.setGravity(Gravity.CENTER);tag.setBackground(stroke(Color.rgb(236,243,255),12,1,Color.rgb(210,226,255)));top.addView(tag,new LinearLayout.LayoutParams(dp(62),dp(34)));box.addView(top);box.addView(tv(x.company+"｜"+x.owner,14,muted,0));box.addView(tv(x.goods+"｜"+x.weight+"｜"+x.vehicleReq,15,Color.rgb(65,76,94),0));box.addView(tv("装货时间："+x.loadTime,14,muted,0));box.addView(tv(x.price,22,orange,Typeface.BOLD));Button b=btn("查看详情 / 立即接单");b.setOnClickListener(v->cargoDetail(x));box.addView(b,new LinearLayout.LayoutParams(-1,dp(46)));}
    void cargoDetail(Cargo x){clear("找货");header("货源详情",x.from+" 至 "+x.to);LinearLayout d=card();d.addView(tv(x.goods+"｜"+x.weight,20,deep,Typeface.BOLD));row(d,"货源编号",x.id);row(d,"货主",x.owner+"｜"+x.company);row(d,"装货位置",x.loadAddr);row(d,"卸货位置",x.unloadAddr);row(d,"车辆要求",x.vehicleReq);row(d,"装货时间",x.loadTime);row(d,"运费",x.price);row(d,"结算方式",x.settlement);row(d,"收货方",x.receiver);row(d,"备注",x.note);Button take=btn("确认接单");take.setOnClickListener(v->{Waybill w=new Waybill(nowNo("YD"),x,"待装货");waybills.add(0,w);Toast.makeText(this,"接单成功，已生成运单",Toast.LENGTH_LONG).show();waybillDetail(w);});d.addView(take,new LinearLayout.LayoutParams(-1,dp(48)));}
    EditText input(String hint){EditText e=new EditText(this);e.setHint(hint);e.setTextSize(15);e.setSingleLine(false);e.setMinLines(1);e.setPadding(dp(14),0,dp(14),0);e.setBackground(stroke(Color.WHITE,14,1,Color.rgb(220,226,237)));LinearLayout.LayoutParams lp=new LinearLayout.LayoutParams(-1,dp(52));lp.setMargins(0,dp(6),0,dp(8));content.addView(e,lp);return e;}void section(String s){TextView t=tv(s,18,deep,Typeface.BOLD);t.setPadding(dp(14),dp(16),dp(14),dp(4));content.addView(t);}
    void showPublish(){clear("发布");header("发布货源","填写货主与货源信息，发布后可在找货大厅接单");section("卖家 / 货主信息");EditText owner=input("货主姓名，例如：赵经理"),phone=input("联系电话"),company=input("公司名称，例如：杭州云仓商贸"),receiver=input("收货方，例如：成都收货仓");section("货物与路线");EditText from=input("出发城市"),to=input("目的城市"),load=input("装货位置"),unload=input("卸货位置"),goods=input("货物名称"),weight=input("装货吨数，例如：10 吨"),time=input("装货时间，例如：今天 18:00");section("运价与要求");EditText price=input("运费，例如：¥3200"),vehicle=input("车辆要求，例如：9.6 米厢式｜带尾板"),settle=input("结算方式，例如：回单后 24 小时结算"),note=input("备注，例如：需拍照回传装货单");Button b=btn("发布货源");b.setOnClickListener(v->{Cargo c=new Cargo(nowNo("HY"),val(owner,"赵经理"),val(phone,"13800009999"),val(company,"优选货主"),val(from,"上海"),val(to,"杭州"),val(load,"装货仓库"),val(unload,"卸货仓库"),val(goods,"普通货物"),val(weight,"待确认"),val(price,"面议"),val(vehicle,"不限车型"),val(time,"今天"),val(settle,"现付"),val(receiver,"收货方"),val(note,"按约定时间装卸"),"新货源");cargos.add(0,c);Toast.makeText(this,"货源已发布",Toast.LENGTH_LONG).show();cargoDetail(c);});content.addView(b,new LinearLayout.LayoutParams(-1,dp(50)));}
    void showMe(){clear("我的");header("我的","司机中心");LinearLayout p=card();p.addView(tv(driverName,22,deep,Typeface.BOLD));p.addView(tv(driverCompany+"｜"+plateNo+"｜"+driverVehicle,15,muted,0));p.addView(tv("手机号："+driverPhone+"｜载重："+driverCapacity,15,muted,0));Button edit=lightBtn("修改司机信息");edit.setOnClickListener(v->editDriver());p.addView(edit,new LinearLayout.LayoutParams(-1,dp(44)));LinearLayout wallet=card();wallet.addView(tv("账户余额",14,muted,0));wallet.addView(tv("¥12,860",30,orange,Typeface.BOLD));content.addView(tv("我的运单",18,deep,Typeface.BOLD));if(waybills.size()==0)content.addView(tv("暂无运单",15,muted,0));for(Waybill w:waybills)waybillCard(w);}void waybillCard(Waybill w){LinearLayout box=card();box.setOnClickListener(v->waybillDetail(w));box.addView(tv(w.status+"｜"+w.c.from+" → "+w.c.to,17,blue,Typeface.BOLD));box.addView(tv("运单号："+w.no,13,muted,0));box.addView(tv(w.c.goods+"｜"+w.c.weight+"｜"+w.c.price,15,Color.rgb(65,76,94),0));box.addView(tv("装货："+w.c.loadTime+"｜"+w.c.loadAddr,14,muted,0));}
    void waybillDetail(Waybill w){clear("我的");header("运单详情",w.no);LinearLayout d=card();d.addView(tv(w.status+"｜"+w.c.from+" → "+w.c.to,20,blue,Typeface.BOLD));row(d,"货主",w.c.owner+"｜"+w.c.company);row(d,"联系电话",w.c.ownerPhone);row(d,"货物",w.c.goods);row(d,"车辆要求",w.c.vehicleReq);row(d,"运费",w.c.price);row(d,"结算方式",w.c.settlement);row(d,"收货方",w.c.receiver);row(d,"备注",w.c.note);section("榜单信息");LinearLayout bill=card();row(bill,"装货位置",w.c.loadAddr);row(bill,"装货吨数",w.c.weight);row(bill,"装货时间",w.c.loadTime);Button up=lightBtn(w.billImage==null?"上传本地榜单图片":"更换榜单图片");up.setOnClickListener(v->{pendingBill=w;Intent it=new Intent(Intent.ACTION_OPEN_DOCUMENT);it.addCategory(Intent.CATEGORY_OPENABLE);it.setType("image/*");startActivityForResult(it,7);});bill.addView(up,new LinearLayout.LayoutParams(-1,dp(44)));if(w.billImage!=null){ImageView img=new ImageView(this);img.setImageURI(w.billImage);img.setScaleType(ImageView.ScaleType.CENTER_CROP);img.setBackgroundColor(Color.rgb(235,239,246));img.setOnClickListener(v->showImage(w.billImage));LinearLayout.LayoutParams ip=new LinearLayout.LayoutParams(-1,dp(190));ip.setMargins(0,dp(10),0,0);bill.addView(img,ip);bill.addView(tv("点击图片放大查看",13,muted,0));}section("运输信息");LinearLayout t=card();row(t,"承运司机",driverName);row(t,"车牌号",plateNo);row(t,"司机电话",driverPhone);row(t,"车辆信息",driverVehicle+"｜"+driverCapacity);Button action=btn(w.status.equals("待装货")?"确认到达装货点":w.status.equals("运输中")?"确认送达":"查看运单");action.setOnClickListener(v->{if(w.status.equals("待装货"))w.status="运输中";else if(w.status.equals("运输中"))w.status="已完成";Toast.makeText(this,"运单状态已更新",Toast.LENGTH_SHORT).show();waybillDetail(w);});t.addView(action,new LinearLayout.LayoutParams(-1,dp(48)));}
    public void onActivityResult(int r,int c,Intent data){super.onActivityResult(r,c,data);if(r==7&&c==RESULT_OK&&data!=null&&pendingBill!=null){Uri u=data.getData();pendingBill.billImage=u;try{getContentResolver().takePersistableUriPermission(u,Intent.FLAG_GRANT_READ_URI_PERMISSION);}catch(Exception e){}Toast.makeText(this,"榜单图片已上传",Toast.LENGTH_SHORT).show();waybillDetail(pendingBill);}}
    void showImage(Uri u){Dialog dlg=new Dialog(this);ImageView im=new ImageView(this);im.setImageURI(u);im.setAdjustViewBounds(true);im.setBackgroundColor(Color.BLACK);im.setOnClickListener(v->dlg.dismiss());dlg.setContentView(im);dlg.show();Window win=dlg.getWindow();if(win!=null)win.setLayout(-1,-1);}void editDriver(){clear("我的");header("修改司机信息","更新承运资料和联系方式");EditText name=input("司机姓名");name.setText(driverName);EditText phone=input("联系电话");phone.setText(driverPhone);EditText plate=input("车牌号");plate.setText(plateNo);EditText vehicle=input("车型车长");vehicle.setText(driverVehicle);EditText cap=input("核载重量");cap.setText(driverCapacity);EditText comp=input("认证/公司信息");comp.setText(driverCompany);Button save=btn("保存信息");save.setOnClickListener(v->{driverName=val(name,driverName);driverPhone=val(phone,driverPhone);plateNo=val(plate,plateNo);driverVehicle=val(vehicle,driverVehicle);driverCapacity=val(cap,driverCapacity);driverCompany=val(comp,driverCompany);Toast.makeText(this,"司机信息已更新",Toast.LENGTH_LONG).show();showMe();});content.addView(save,new LinearLayout.LayoutParams(-1,dp(50)));}
}
